import React, { useState } from 'react';
import './ItemsPage.css';
import { itemsData } from '../data/itemsData';

const ItemsPage = () => {
  const [items] = useState(itemsData);

  return (
    <div className="items-page">
      <div className="items-page-content">
        {/* Page Header */}
        <div className="items-header">
          <h1 className="items-title">All Items</h1>
          <p className="items-description">
            Explore our collection of Korean dishes, drinks, and desserts. 
            Each item is crafted with authentic recipes and love.
          </p>
        </div>

        {/* Items Grid - 4 columns × dynamic rows */}
        <div className="items-grid">
          {items.map((item) => (
            <div key={item.id} className="item-card">
              <div className="item-image-container">
                <img 
                  src={item.image} 
                  alt={item.name}
                  className="item-image"
                />
              </div>
              <div className="item-info">
                <h3 className="item-name">{item.name}</h3>
              </div>
            </div>
          ))}
        </div>

        {/* Items Count */}
        <div className="items-count">
          <p>Showing {items.length} items</p>
        </div>
      </div>
    </div>
  );
};

export default ItemsPage;
